import React, { useState, useContext } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import Navbar from './Navbar';
import Footer from './Footer';
import axios from 'axios';
import { AuthContext } from '../context/AuthContext';

const Login = () => {
  const [formData, setFormData] = useState({
    email: '',
    password: ''
  });
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);
  const navigate = useNavigate();
  const { login } = useContext(AuthContext);

  const handleChange = (e) => {
    setFormData({ ...formData, [e.target.name]: e.target.value });
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    setError('');
    
    try {
      // Mocking a successful login
      console.log('Logging in with:', formData);
      
      // Simulate API call
      setTimeout(() => {
        const mockUser = { name: 'User', email: formData.email };
        login(mockUser);
        setLoading(false);
        navigate('/');
      }, 1000);

    } catch (err) {
      setLoading(false);
      setError(err.response?.data?.message || 'Something went wrong. Please try again.');
    }
  };

  return (
    <div className="sub_page">
      <div className="hero_area">
        <div className="bg-box">
          <img src="image/hero-bg.jpg" alt="" />
        </div>
        <Navbar />
      </div>

      <section className="booking_section layout_padding">
        <div className="container">
          <div className="heading_container">
            <h2 className="section-title">Login</h2>
          </div>
          <div className="row">
            <div className="col-md-6 mx-auto">
              <div className="form_container">
                <form onSubmit={handleSubmit}>
                  {error && <div style={{ color: 'red', marginBottom: '10px' }}>{error}</div>}
                  <div>
                    <input
                      type="email"
                      name="email"
                      className="form-control input-field"
                      placeholder="Your Email"
                      value={formData.email}
                      onChange={handleChange}
                      required
                    />
                  </div>
                  <div>
                    <input
                      type="password"
                      name="password"
                      className="form-control input-field"
                      placeholder="Password"
                      value={formData.password}
                      onChange={handleChange}
                      required
                    />
                  </div>
                  <div className="btn_box">
                    <button type="submit" className="book-btn" disabled={loading}>
                      {loading ? 'Logging in...' : 'Login'}
                    </button>
                  </div>
                </form>
                <div style={{ marginTop: '20px', textAlign: 'center' }}>
                  <p>Don't have an account? <Link to="/register" style={{ color: 'var(--primary-color)' }}>Register here</Link></p>
                </div>
              </div>
            </div>
          </div>
        </div>
      </section>

      <Footer />
    </div>
  );
};

export default Login;
